import heapq

class Solution:
    def minimumWeight(self, n, edges, src1, src2, dest):
        adj = [[] for _ in range(n)]
        radj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
            radj[v].append((u, w))

        def dijkstra(graph, source):
            dist = [float('inf')] * n
            dist[source] = 0
            pq = [(0, source)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                for v, w in graph[u]:
                    nd = d + w
                    if nd < dist[v]:
                        dist[v] = nd
                        heapq.heappush(pq, (nd, v))
            return dist

        d1 = dijkstra(adj, src1)
        d2 = dijkstra(adj, src2)
        d3 = dijkstra(radj, dest)
        best = float('inf')
        for m in range(n):
            if d1[m] == float('inf') or d2[m] == float('inf') or d3[m] == float('inf'):
                continue
            total = d1[m] + d2[m] + d3[m]
            if total < best:
                best = total
        return -1 if best == float('inf') else best

