class MinHeap {
    constructor() { this.data = []; }
    push(item) {
        this.data.push(item);
        let i = this.data.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (this.data[p][0] <= this.data[i][0]) break;
            [this.data[p], this.data[i]] = [this.data[i], this.data[p]];
            i = p;
        }
    }
    pop() {
        const top = this.data[0];
        const last = this.data.pop();
        if (this.data.length) {
            this.data[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, s = i;
                if (l < this.data.length && this.data[l][0] < this.data[s][0]) s = l;
                if (r < this.data.length && this.data[r][0] < this.data[s][0]) s = r;
                if (s === i) break;
                [this.data[s], this.data[i]] = [this.data[i], this.data[s]];
                i = s;
            }
        }
        return top;
    }
    get size() { return this.data.length; }
}

var minimumWeight = function(n, edges, src1, src2, dest) {
    const adj = Array.from({ length: n }, () => []);
    const radj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        radj[v].push([u, w]);
    }

    function dijkstra(graph, source) {
        const dist = new Array(n).fill(-1);
        dist[source] = 0;
        const heap = new MinHeap();
        heap.push([0, source]);
        while (heap.size) {
            const [d, u] = heap.pop();
            if (dist[u] !== -1 && d > dist[u]) continue;
            for (const [v, w] of graph[u]) {
                const nd = d + w;
                if (dist[v] === -1 || nd < dist[v]) {
                    dist[v] = nd;
                    heap.push([nd, v]);
                }
            }
        }
        return dist;
    }

    const d1 = dijkstra(adj, src1);
    const d2 = dijkstra(adj, src2);
    const d3 = dijkstra(radj, dest);
    let best = -1;
    for (let m = 0; m < n; m++) {
        if (d1[m] === -1 || d2[m] === -1 || d3[m] === -1) continue;
        const total = d1[m] + d2[m] + d3[m];
        if (best === -1 || total < best) best = total;
    }
    return best;
};
